public struct WalletSummary {
    public var id: String
    public var name: String
    public var isWatchOnly: Bool
    public var selectedChain: String?
    public var includeInPortfolioTotal: Bool
    public var bitcoinNetworkMode: String
    public var dogecoinNetworkMode: String
    public var bitcoinXpub: String?
    public var derivationPreset: String
    public var derivationPaths: [String: String]
    public var holdings: [AssetHolding]
    public var addresses: [WalletAddress]

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(id: String, name: String, isWatchOnly: Bool, selectedChain: String?, includeInPortfolioTotal: Bool, bitcoinNetworkMode: String, dogecoinNetworkMode: String, bitcoinXpub: String?, derivationPreset: String, derivationPaths: [String: String], holdings: [AssetHolding], addresses: [WalletAddress]) {
        self.id = id
        self.name = name
        self.isWatchOnly = isWatchOnly
        self.selectedChain = selectedChain
        self.includeInPortfolioTotal = includeInPortfolioTotal
        self.bitcoinNetworkMode = bitcoinNetworkMode
        self.dogecoinNetworkMode = dogecoinNetworkMode
        self.bitcoinXpub = bitcoinXpub
        self.derivationPreset = derivationPreset
        self.derivationPaths = derivationPaths
        self.holdings = holdings
        self.addresses = addresses
    }
}

#if compiler(>=6)
extension WalletSummary: Sendable {}
#endif


extension WalletSummary: Equatable, Hashable {
    public static func ==(lhs: WalletSummary, rhs: WalletSummary) -> Bool {
        if lhs.id != rhs.id {
            return false
        }
        if lhs.name != rhs.name {
            return false
        }
        if lhs.isWatchOnly != rhs.isWatchOnly {
            return false
        }
        if lhs.selectedChain != rhs.selectedChain {
            return false
        }
        if lhs.includeInPortfolioTotal != rhs.includeInPortfolioTotal {
            return false
        }
        if lhs.bitcoinNetworkMode != rhs.bitcoinNetworkMode {
            return false
        }
        if lhs.dogecoinNetworkMode != rhs.dogecoinNetworkMode {
            return false
        }
        if lhs.bitcoinXpub != rhs.bitcoinXpub {
            return false
        }
        if lhs.derivationPreset != rhs.derivationPreset {
            return false
        }
        if lhs.derivationPaths != rhs.derivationPaths {
            return false
        }
        if lhs.holdings != rhs.holdings {
            return false
        }
        if lhs.addresses != rhs.addresses {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(id)
        hasher.combine(name)
        hasher.combine(isWatchOnly)
        hasher.combine(selectedChain)
        hasher.combine(includeInPortfolioTotal)
        hasher.combine(bitcoinNetworkMode)
        hasher.combine(dogecoinNetworkMode)
        hasher.combine(bitcoinXpub)
        hasher.combine(derivationPreset)
        hasher.combine(derivationPaths)
        hasher.combine(holdings)
        hasher.combine(addresses)
    }
}



